SERVO_PINS = {1: 5, 2: 6}
PULSO_MIN = 500    
PULSO_MAX = 2500   

def angulo_a_pulso(angulo: int) -> int:
    return int(PULSO_MIN + (angulo / 180.0) * (PULSO_MAX - PULSO_MIN))



