import ARROZ_rc


class MainWindow(QtWidgets.QDialog):
    def __init__(self):
        super().__init__()
        self.ui = Ui_Dialog()
        self.ui.setupUi(self)

        self.ui.horizontalSlider.setRange(0, 180)
        self.ui.horizontalSlider_2.setRange(0, 180)

        # Inicializar pigpio
        if GPIO_AVAILABLE:
            self.pi = pigpio.pi()
            if not self.pi.connected:
                print("Error: No se pudo conectar al demonio pigpiod.")
                self.pi = None
        else:
            self.pi = None

        # Conexiones
        self.ui.horizontalSlider.valueChanged.connect(self._actualizar_servo1)
        self.ui.horizontalSlider_2.valueChanged.connect(self._actualizar_servo2)
        self.ui.pushButton.clicked.connect(self._click_ok)

    def _click_ok(self):
        txt = self.ui.lineEdit.text()
        if txt in ["1", "2"]:
            QtWidgets.QMessageBox.information(self, "Selección", f"Servo {txt} listo para control.")
        else:
            QtWidgets.QMessageBox.warning(self, "Error", "Por favor ingresa 1 o 2.")

    def _actualizar_servo1(self, v):
        self.ui.label_5.setText(f"{v}°")
        if self.pi: self.pi.set_servo_pulsewidth(SERVO_PINS[1], angulo_a_pulso(v))

    def _actualizar_servo2(self, v):
        self.ui.label_6.setText(f"{v}°")
        if self.pi: self.pi.set_servo_pulsewidth(SERVO_PINS[2], angulo_a_pulso(v))

    def closeEvent(self, event):
        if self.pi:
            for p in SERVO_PINS.values(): self.pi.set_servo_pulsewidth(p, 0)
            self.pi.stop()
        event.accept()

if __name__ == "__main__":
    app = QtWidgets.QApplication(sys.argv)
    v = MainWindow()
    v.show()
    sys.exit(app.exec_())